// DbContext với multi-tenancy + soft delete
public class AppDbContext(
    DbContextOptions<AppDbContext> options,
    ICurrentTenantService tenant) : DbContext(options)
{
    protected override void OnModelCreating(ModelBuilder model)
    {
        // Multi-tenancy filter
        foreach (var entityType in model.Model.GetEntityTypes()
            .Where(e => typeof(ITenantEntity).IsAssignableFrom(e.ClrType)))
        {
            model.Entity(entityType.ClrType).HasQueryFilter(
                e => EF.Property<int>(e, "TenantId") == tenant.CurrentTenantId);
        }

        // Soft delete filter
        foreach (var entityType in model.Model.GetEntityTypes()
            .Where(e => typeof(ISoftDelete).IsAssignableFrom(e.ClrType)))
        {
            model.Entity(entityType.ClrType).HasQueryFilter(
                e => !EF.Property<bool>(e, "IsDeleted"));
        }
    }
}

